Recursion is when a function calls itself. Every recursive function needs a base case (stops recursion) and a recursive case:
```javascript
// Factorial: n! = n * (n-1)!
function factorial(n) {
  if (n <= 1) return 1; // base case
  return n * factorial(n - 1); // recursive case
}

// Fibonacci
function fib(n) {
  if (n <= 1) return n;
  return fib(n-1) + fib(n-2);
}

// Tree traversal
function traverse(node) {
  if (!node) return;
  traverse(node.left);
  console.log(node.value);
  traverse(node.right);
}
```

