```javascript
let todos = JSON.parse(localStorage.getItem('todos') || '[]');

function save() { localStorage.setItem('todos', JSON.stringify(todos)); }

function render() {
  document.getElementById('todo-list').innerHTML = todos.map((todo, i) => `
    <li class="${todo.done ? 'done' : ''}">
      <input type="checkbox" ${todo.done ? 'checked' : ''} onchange="toggle(${i})">
      <span>${todo.text}</span>
      <button onclick="remove(${i})">✕</button>
    </li>`).join('');
}

function addTodo() {
  const text = document.getElementById('todo-text').value.trim();
  if (!text) return;
  todos.push({ text, done: false });
  document.getElementById('todo-text').value = '';
  save(); render();
}

function toggle(i) { todos[i].done = !todos[i].done; save(); render(); }
function remove(i) { todos.splice(i, 1); save(); render(); }

document.getElementById('todo-text').addEventListener('keypress', e => {
  if (e.key === 'Enter') addTodo();
});

render();
```

```javascript
/**
 * Debounce: delays execution until after 'delay' ms have passed
 * since the last call. Good for search inputs, resize handlers.
 */
function debounce(fn, delay = 300) {
  let timeoutId;
  return function (...args) {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => fn.apply(this, args), delay);
  };
}

// Usage
const search = debounce((query) => {
  console.log('Searching:', query);
  fetchResults(query);
}, 400);

input.addEventListener('input', (e) => search(e.target.value));

// Throttle (limit to once per interval):
function throttle(fn, limit = 300) {
  let lastRun = 0;
  return function (...args) {
    const now = Date.now();
    if (now - lastRun >= limit) {
      lastRun = now;
      fn.apply(this, args);
    }
  };
}
```

