```javascript
let current = '0', prev = '', op = null;
const display = document.getElementById('display');
function update(v) { display.textContent = current = String(v); }
function input(v) { current = current === '0' ? v : current + v; display.textContent = current; }
function inputOp(o) { prev = current; op = o; current = '0'; }
function clearAll() { current = '0'; prev = ''; op = null; display.textContent = '0'; }
function calculate() {
  if (!op || !prev) return;
  const a = parseFloat(prev), b = parseFloat(current);
  const results = {'+': a+b, '-': a-b, '*': a*b, '/': a/b};
  update(Math.round(results[op] * 1e10) / 1e10);
  op = null;
}
```
